from qiskit.quantum_info import Statevector
from qiskit.visualization import plot_bloch_vector, plot_bloch_multivector
import matplotlib

def accepts(fn):
    try:
        return isinstance(fn(), matplotlib.figure.Figure)
    except Exception:
        return False

bv_vec = accepts(lambda: plot_bloch_vector([0, 0, 1]))
bv_state = accepts(lambda: plot_bloch_vector(Statevector.from_label("+")))
mv_vec = accepts(lambda: plot_bloch_multivector([0, 0, 1]))
mv_state = accepts(lambda: plot_bloch_multivector(Statevector.from_label("+")))

evidence = {}
proven = []
mA = bv_state and mv_state
evidence["A"] = f"plot_bloch_vector accepts a state={bv_state}, plot_bloch_multivector accepts a state={mv_state}; 'both take a state' match={mA}"
if mA:
    proven.append("A")
mB = bv_state and mv_vec
evidence["B"] = f"plot_bloch_vector accepts a state={bv_state}, plot_bloch_multivector accepts a 3-vector={mv_vec}; reversed claim match={mB}"
if mB:
    proven.append("B")
mC = bv_vec and mv_state and (not mv_vec)
evidence["C"] = f"plot_bloch_vector accepts [x,y,z]={bv_vec}; plot_bloch_multivector accepts a state={mv_state} and rejects a 3-vector={not mv_vec}; match={mC}"
if mC:
    proven.append("C")
mD = bv_vec and mv_vec
evidence["D"] = f"plot_bloch_vector accepts [x,y,z]={bv_vec}, plot_bloch_multivector accepts [x,y,z]={mv_vec}; 'both take a 3-vector' match={mD}"
if mD:
    proven.append("D")

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"bv_vec": bv_vec, "bv_state": bv_state, "mv_vec": mv_vec, "mv_state": mv_state},
})
